sp_widget.client_script:
api.controller=function() {
  /* widget controller */
  var c = this;
};

sp_widget.css:
.enams-hero{

    position:relative;
    overflow:hidden;
    text-align:center;
    padding:100px 30px;
    background:linear-gradient(135deg,#f5f7fa,#eef3f8);
    border-radius:22px;
    box-shadow:0 15px 35px rgba(15,76,129,.12);
    margin:20px;
    transition:.4s;

}

.enams-hero::before{

    content:"";
    position:absolute;
    top:0;
    left:-120%;
    width:100%;
    height:100%;
    background:linear-gradient(
        90deg,
        transparent,
        rgba(255,255,255,.45),
        transparent
    );

    transition:1s;

}

.enams-hero:hover::before{

    left:120%;

}

.enams-hero:hover{

    transform:translateY(-5px);

}

.enams-hero h1{

    color:#0F4C81;
    font-size:56px;
    font-weight:700;
    margin-bottom:20px;
    line-height:1.2;

}

.subtitle{

    font-size:24px;
    font-weight:600;
    color:#D4A017;
    margin-bottom:25px;

}

.description{

    max-width:850px;
    margin:auto;
    font-size:19px;
    color:#555;
    line-height:1.9;
    margin-bottom:45px;

}

.hero-btn{

    background:linear-gradient(135deg,#0F4C81,#1E6BB8);
    color:#ffffff;
    border:none;
    padding:18px 42px;
    font-size:18px;
    font-weight:bold;
    border-radius:10px;
    cursor:pointer;
    transition:.35s;
    box-shadow:0 10px 22px rgba(15,76,129,.25);

}

.hero-btn:hover{

    background:linear-gradient(135deg,#0B3A62,#0F4C81);
    transform:translateY(-4px);
    box-shadow:0 16px 32px rgba(15,76,129,.35);

}

@media(max-width:992px){

    .enams-hero{

        padding:80px 25px;

    }

    .enams-hero h1{

        font-size:46px;

    }

    .description{

        max-width:90%;

    }

}

@media(max-width:768px){

    .enams-hero{

        padding:60px 20px;
        margin:10px;

    }

    .enams-hero h1{

        font-size:34px;

    }

    .subtitle{

        font-size:20px;

    }

    .description{

        font-size:16px;
        max-width:100%;

    }

    .hero-btn{

        width:100%;

    }

}
